import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Product {
  id: string;
  code: string;
  name: string;
  barcode: string;
  purchasePrice: number;
  sellingPrice: number;
  stock: number;
  category: string;
}

export interface TransactionItem {
  productId: string;
  name: string;
  price: number;
  quantity: number;
  subtotal: number;
}

export type TransactionType = 'IN' | 'OUT';

export interface Transaction {
  id: string;
  date: string;
  type: TransactionType;
  items: TransactionItem[];
  total: number;
  paymentAmount?: number;
  changeAmount?: number;
  note?: string;
}

export interface MonthlyStats {
  month: string;
  incoming: number;
  outgoing: number;
}

export const formatCurrency = (amount: number): string => {
  return new Intl.NumberFormat('id-ID', {
    style: 'decimal',
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
  }).format(amount);
};

export const parseFormattedNumber = (value: string): number => {
  return Number(value.replace(/[^0-9]/g, ''));
};

export const generateId = () => Math.random().toString(36).substr(2, 9).toUpperCase();

export const formatDate = (date: string | Date) => {
  return new Intl.DateTimeFormat('id-ID', {
    dateStyle: 'medium',
    timeStyle: 'short',
  }).format(new Date(date));
};

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, NavLink, useLocation } from 'react-router-dom';
import { 
  LayoutDashboard, 
  Package, 
  ShoppingCart, 
  History, 
  FileText, 
  Menu, 
  X,
  Bell,
  User
} from 'lucide-react';

import Dashboard from './pages/Dashboard';
import Products from './pages/Products';
import POS from './pages/POS';
import Transactions from './pages/Transactions';
import Reports from './pages/Reports';
import { Product, Transaction } from './types';

// Initial Mock Data
const INITIAL_PRODUCTS: Product[] = [
  { id: '1', code: 'BRG001', name: 'Premium Arabica Coffee', barcode: '899123456001', purchasePrice: 45000, sellingPrice: 65000, stock: 45, category: 'Beverage' },
  { id: '2', code: 'BRG002', name: 'Silk Road Tea', barcode: '899123456002', purchasePrice: 20000, sellingPrice: 35000, stock: 12, category: 'Beverage' },
  { id: '3', code: 'BRG003', name: 'Organic Honey 500ml', barcode: '899123456003', purchasePrice: 75000, sellingPrice: 98000, stock: 5, category: 'Food' },
  { id: '4', code: 'BRG004', name: 'Dark Chocolate Bar', barcode: '899123456004', purchasePrice: 15000, sellingPrice: 25000, stock: 120, category: 'Food' },
  { id: '5', code: 'BRG005', name: 'Artisan Sourdough', barcode: '899123456005', purchasePrice: 18000, sellingPrice: 32000, stock: 2, category: 'Food' },
];

const SidebarItem: React.FC<{ to: string, icon: React.ReactNode, label: string, onClick?: () => void }> = ({ to, icon, label, onClick }) => {
  return (
    <NavLink 
      to={to} 
      onClick={onClick}
      className={({ isActive }) => `
        flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-200
        ${isActive 
          ? 'bg-purple-600 text-white shadow-lg shadow-purple-200' 
          : 'text-slate-500 hover:bg-purple-50 hover:text-purple-600'}
      `}
    >
      {icon}
      <span className="font-semibold">{label}</span>
    </NavLink>
  );
};

const App: React.FC = () => {
  const [products, setProducts] = useState<Product[]>(INITIAL_PRODUCTS);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // Sync products with stock changes from transactions
  const handleAddTransaction = (newTx: Transaction) => {
    setTransactions(prev => [newTx, ...prev]);
    setProducts(prevProducts => {
      return prevProducts.map(p => {
        const item = newTx.items.find(i => i.productId === p.id);
        if (item) {
          const stockChange = newTx.type === 'OUT' ? -item.quantity : item.quantity;
          return { ...p, stock: Math.max(0, p.stock + stockChange) };
        }
        return p;
      });
    });
  };

  return (
    <HashRouter>
      <div className="flex min-h-screen bg-slate-50">
        {/* Mobile Sidebar Overlay */}
        {isSidebarOpen && (
          <div 
            className="fixed inset-0 bg-black/50 z-40 lg:hidden"
            onClick={() => setIsSidebarOpen(false)}
          />
        )}

        {/* Sidebar */}
        <aside className={`
          fixed inset-y-0 left-0 z-50 w-64 bg-white border-r border-slate-200 transform transition-transform duration-300 ease-in-out lg:relative lg:translate-x-0
          ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
        `}>
          <div className="p-6">
            <div className="flex items-center gap-2 mb-8">
              <div className="bg-purple-600 p-2 rounded-lg">
                <Package className="text-white h-6 w-6" />
              </div>
              <h1 className="text-xl font-bold bg-gradient-to-r from-purple-600 to-indigo-600 bg-clip-text text-transparent">
                InvMaster
              </h1>
            </div>

            <nav className="space-y-2">
              <SidebarItem to="/" icon={<LayoutDashboard size={20} />} label="Dashboard" onClick={() => setIsSidebarOpen(false)} />
              <SidebarItem to="/products" icon={<Package size={20} />} label="Manajemen Barang" onClick={() => setIsSidebarOpen(false)} />
              <SidebarItem to="/pos" icon={<ShoppingCart size={20} />} label="Kasir" onClick={() => setIsSidebarOpen(false)} />
              <SidebarItem to="/transactions" icon={<History size={20} />} label="Riwayat Transaksi" onClick={() => setIsSidebarOpen(false)} />
              <SidebarItem to="/reports" icon={<FileText size={20} />} label="Laporan" onClick={() => setIsSidebarOpen(false)} />
            </nav>
          </div>

          <div className="absolute bottom-0 w-full p-6 border-t border-slate-100">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center">
                <User size={20} className="text-slate-400" />
              </div>
              <div>
                <p className="text-sm font-bold text-slate-700">Admin Utama</p>
                <p className="text-xs text-slate-500">Super Admin</p>
              </div>
            </div>
          </div>
        </aside>

        {/* Main Content */}
        <main className="flex-1 flex flex-col min-w-0">
          {/* Header */}
          <header className="sticky top-0 z-30 flex items-center justify-between h-16 px-4 bg-white border-b border-slate-200 lg:px-8">
            <div className="flex items-center gap-4">
              <button 
                onClick={() => setIsSidebarOpen(true)}
                className="p-2 -ml-2 text-slate-500 rounded-lg hover:bg-slate-100 lg:hidden"
              >
                <Menu size={24} />
              </button>
              <h2 className="text-lg font-bold text-slate-800 lg:text-xl">
                {/* Dynamic Title logic could go here */}
              </h2>
            </div>

            <div className="flex items-center gap-2">
              <button className="p-2 text-slate-500 rounded-lg hover:bg-slate-100 relative">
                <Bell size={20} />
                <span className="absolute top-1 right-1 w-2 h-2 bg-red-500 rounded-full border-2 border-white"></span>
              </button>
            </div>
          </header>

          <div className="p-4 lg:p-8 flex-1 overflow-y-auto">
            <Routes>
              <Route path="/" element={<Dashboard products={products} transactions={transactions} />} />
              <Route path="/products" element={<Products products={products} setProducts={setProducts} onStockEntry={(tx) => handleAddTransaction(tx)} />} />
              <Route path="/pos" element={<POS products={products} onCheckout={handleAddTransaction} />} />
              <Route path="/transactions" element={<Transactions transactions={transactions} />} />
              <Route path="/reports" element={<Reports transactions={transactions} products={products} />} />
            </Routes>
          </div>
        </main>
      </div>
    </HashRouter>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { 
  TrendingUp, 
  TrendingDown, 
  Package, 
  AlertTriangle,
  ChevronDown,
  ArrowUpRight,
  ArrowDownRight
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer,
  Cell,
  Legend
} from 'recharts';
import { Product, Transaction, MonthlyStats } from '../types';
import { formatCurrency } from '../utils';

interface DashboardProps {
  products: Product[];
  transactions: Transaction[];
}

const KPICard: React.FC<{ 
  title: string, 
  value: string | number, 
  icon: React.ReactNode, 
  color: string,
  subtitle?: string,
  trend?: { type: 'up' | 'down', value: string }
}> = ({ title, value, icon, color, subtitle, trend }) => (
  <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm flex flex-col gap-4">
    <div className="flex justify-between items-start">
      <div className={`${color} p-3 rounded-xl`}>
        {icon}
      </div>
      {trend && (
        <div className={`flex items-center gap-1 text-xs font-bold px-2 py-1 rounded-full ${trend.type === 'up' ? 'text-emerald-600 bg-emerald-50' : 'text-rose-600 bg-rose-50'}`}>
          {trend.type === 'up' ? <ArrowUpRight size={14} /> : <ArrowDownRight size={14} />}
          {trend.value}
        </div>
      )}
    </div>
    <div>
      <p className="text-slate-500 text-sm font-medium">{title}</p>
      <h3 className="text-2xl font-bold text-slate-800">{value}</h3>
      {subtitle && <p className="text-xs text-slate-400 mt-1">{subtitle}</p>}
    </div>
  </div>
);

const Dashboard: React.FC<DashboardProps> = ({ products, transactions }) => {
  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());

  const years = useMemo(() => {
    const startYear = 2022;
    const currentYear = new Date().getFullYear();
    const result = [];
    for (let i = currentYear; i >= startYear; i--) result.push(i);
    return result;
  }, []);

  const stats = useMemo(() => {
    const totalStock = products.reduce((acc, p) => acc + p.stock, 0);
    const lowStockCount = products.filter(p => p.stock <= 5).length;

    const incoming = transactions
      .filter(t => t.type === 'IN')
      .reduce((acc, t) => acc + t.items.reduce((sum, item) => sum + item.quantity, 0), 0);

    const outgoing = transactions
      .filter(t => t.type === 'OUT')
      .reduce((acc, t) => acc + t.items.reduce((sum, item) => sum + item.quantity, 0), 0);

    return { totalStock, lowStockCount, incoming, outgoing };
  }, [products, transactions]);

  const chartData: MonthlyStats[] = useMemo(() => {
    const months = ['Jan', 'Feb', 'Mar', 'Apr', 'Mei', 'Jun', 'Jul', 'Agu', 'Sep', 'Okt', 'Nov', 'Des'];
    return months.map((month, index) => {
      const filtered = transactions.filter(t => {
        const d = new Date(t.date);
        return d.getMonth() === index && d.getFullYear() === selectedYear;
      });

      return {
        month,
        incoming: filtered
          .filter(t => t.type === 'IN')
          .reduce((acc, t) => acc + t.items.reduce((sum, i) => sum + i.quantity, 0), 0),
        outgoing: filtered
          .filter(t => t.type === 'OUT')
          .reduce((acc, t) => acc + t.items.reduce((sum, i) => sum + i.quantity, 0), 0)
      };
    });
  }, [transactions, selectedYear]);

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-800">Ringkasan Gudang</h1>
          <p className="text-slate-500">Pantau pergerakan stok barang secara real-time</p>
        </div>

        {/* Year Selector Logic */}
        <div className="bg-white p-1 rounded-xl border border-slate-100 flex items-center shadow-sm">
          {years.length <= 4 ? (
            years.map(y => (
              <button
                key={y}
                onClick={() => setSelectedYear(y)}
                className={`px-4 py-2 rounded-lg text-sm font-semibold transition-all ${
                  selectedYear === y ? 'bg-purple-600 text-white shadow-md' : 'text-slate-500 hover:text-purple-600'
                }`}
              >
                {y}
              </button>
            ))
          ) : (
            <div className="relative inline-block">
              <select 
                value={selectedYear}
                onChange={(e) => setSelectedYear(Number(e.target.value))}
                className="appearance-none bg-transparent pl-4 pr-10 py-2 rounded-lg text-sm font-semibold text-slate-700 focus:outline-none cursor-pointer"
              >
                {years.map(y => <option key={y} value={y}>{y}</option>)}
              </select>
              <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={16} />
            </div>
          )}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <KPICard 
          title="Total Stok Tersedia" 
          value={formatCurrency(stats.totalStock)} 
          icon={<Package className="text-purple-600" />} 
          color="bg-purple-50"
          trend={{ type: 'up', value: '+12%' }}
        />
        <KPICard 
          title="Barang Masuk" 
          value={formatCurrency(stats.incoming)} 
          icon={<TrendingUp className="text-blue-600" />} 
          color="bg-blue-50"
          subtitle="Total periode ini"
        />
        <KPICard 
          title="Barang Keluar" 
          value={formatCurrency(stats.outgoing)} 
          icon={<TrendingDown className="text-rose-600" />} 
          color="bg-rose-50"
          subtitle="Total periode ini"
        />
        <KPICard 
          title="Stok Menipis" 
          value={stats.lowStockCount} 
          icon={<AlertTriangle className="text-amber-600" />} 
          color="bg-amber-50"
          subtitle="Segera restock barang"
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Main Chart */}
        <div className="lg:col-span-2 bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
          <div className="flex items-center justify-between mb-8">
            <h3 className="font-bold text-slate-800 text-lg">Statistik Pergerakan Barang {selectedYear}</h3>
            <div className="flex gap-4">
              <div className="flex items-center gap-2 text-xs font-semibold text-slate-500">
                <span className="w-3 h-3 bg-purple-500 rounded-sm"></span> Masuk
              </div>
              <div className="flex items-center gap-2 text-xs font-semibold text-slate-500">
                <span className="w-3 h-3 bg-slate-200 rounded-sm"></span> Keluar
              </div>
            </div>
          </div>
          <div className="h-[350px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis 
                  dataKey="month" 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fill: '#64748b', fontSize: 12 }}
                  dy={10}
                />
                <YAxis 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fill: '#64748b', fontSize: 12 }} 
                  label={{ value: 'Jumlah Unit', angle: -90, position: 'insideLeft', offset: 10, style: { fontSize: 12, fill: '#94a3b8' }}}
                />
                <Tooltip 
                  cursor={{ fill: '#f8fafc' }}
                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)' }}
                />
                <Bar 
                  dataKey="incoming" 
                  name="Masuk" 
                  fill="#9333ea" 
                  radius={[4, 4, 0, 0]} 
                  barSize={20}
                />
                <Bar 
                  dataKey="outgoing" 
                  name="Keluar" 
                  fill="#e2e8f0" 
                  radius={[4, 4, 0, 0]} 
                  barSize={20}
                />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Low Stock Sidebar */}
        <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
          <h3 className="font-bold text-slate-800 text-lg mb-6 flex items-center gap-2">
            Peringatan Stok <span className="text-xs bg-rose-500 text-white px-2 py-0.5 rounded-full">{stats.lowStockCount}</span>
          </h3>
          <div className="space-y-4">
            {products
              .filter(p => p.stock <= 10)
              .sort((a, b) => a.stock - b.stock)
              .slice(0, 6)
              .map(p => (
                <div key={p.id} className="flex items-center justify-between p-3 rounded-xl hover:bg-slate-50 transition-colors border border-transparent hover:border-slate-100">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-lg bg-slate-100 flex items-center justify-center font-bold text-slate-400">
                      {p.name.charAt(0)}
                    </div>
                    <div>
                      <p className="text-sm font-bold text-slate-700 leading-tight">{p.name}</p>
                      <p className="text-xs text-slate-400 uppercase tracking-wider">{p.code}</p>
                    </div>
                  </div>
                  <div className={`text-sm font-bold px-2 py-1 rounded ${p.stock <= 5 ? 'text-rose-600 bg-rose-50' : 'text-amber-600 bg-amber-50'}`}>
                    {p.stock} <span className="text-[10px] font-medium opacity-70">pcs</span>
                  </div>
                </div>
              ))}
            {stats.lowStockCount === 0 && (
              <div className="text-center py-10">
                <div className="w-16 h-16 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center mx-auto mb-4">
                  <Package size={32} />
                </div>
                <p className="text-slate-500 text-sm">Semua stok terpantau aman.</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { 
  Plus, 
  Search, 
  Edit2, 
  Trash2, 
  Barcode, 
  Filter,
  ArrowUpDown,
  Download,
  Upload
} from 'lucide-react';
import { Product, Transaction } from '../types';
import { formatCurrency, parseFormattedNumber, generateId } from '../utils';

interface ProductsProps {
  products: Product[];
  setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
  onStockEntry: (tx: Transaction) => void;
}

const Products: React.FC<ProductsProps> = ({ products, setProducts, onStockEntry }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [showModal, setShowModal] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [formData, setFormData] = useState({
    code: '',
    name: '',
    barcode: '',
    purchasePrice: '0',
    sellingPrice: '0',
    stock: '0',
    category: ''
  });

  const handleOpenModal = (p?: Product) => {
    if (p) {
      setEditingProduct(p);
      setFormData({
        code: p.code,
        name: p.name,
        barcode: p.barcode,
        purchasePrice: formatCurrency(p.purchasePrice),
        sellingPrice: formatCurrency(p.sellingPrice),
        stock: p.stock.toString(),
        category: p.category
      });
    } else {
      setEditingProduct(null);
      setFormData({
        code: `BRG${Math.floor(Math.random() * 900) + 100}`,
        name: '',
        barcode: '',
        purchasePrice: '0',
        sellingPrice: '0',
        stock: '0',
        category: ''
      });
    }
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const productData: Product = {
      id: editingProduct ? editingProduct.id : generateId(),
      code: formData.code,
      name: formData.name,
      barcode: formData.barcode,
      purchasePrice: parseFormattedNumber(formData.purchasePrice),
      sellingPrice: parseFormattedNumber(formData.sellingPrice),
      stock: parseInt(formData.stock),
      category: formData.category
    };

    if (editingProduct) {
      // If stock increased manually, track as IN transaction
      if (productData.stock > editingProduct.stock) {
        const diff = productData.stock - editingProduct.stock;
        onStockEntry({
          id: generateId(),
          date: new Date().toISOString(),
          type: 'IN',
          total: productData.purchasePrice * diff,
          items: [{
            productId: productData.id,
            name: productData.name,
            price: productData.purchasePrice,
            quantity: diff,
            subtotal: productData.purchasePrice * diff
          }]
        });
      }
      setProducts(prev => prev.map(p => p.id === editingProduct.id ? productData : p));
    } else {
      setProducts(prev => [...prev, productData]);
      if (productData.stock > 0) {
        onStockEntry({
          id: generateId(),
          date: new Date().toISOString(),
          type: 'IN',
          total: productData.purchasePrice * productData.stock,
          items: [{
            productId: productData.id,
            name: productData.name,
            price: productData.purchasePrice,
            quantity: productData.stock,
            subtotal: productData.purchasePrice * productData.stock
          }]
        });
      }
    }
    setShowModal(false);
  };

  const handleDelete = (id: string) => {
    if (confirm('Hapus barang ini?')) {
      setProducts(prev => prev.filter(p => p.id !== id));
    }
  };

  const filteredProducts = products.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    p.code.toLowerCase().includes(searchTerm.toLowerCase()) ||
    p.barcode.includes(searchTerm)
  );

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-800">Manajemen Barang</h1>
          <p className="text-slate-500">Kelola master data produk dan stok inventaris</p>
        </div>
        <div className="flex gap-2">
          <button className="flex items-center gap-2 px-4 py-2 border border-slate-200 bg-white rounded-xl text-sm font-semibold text-slate-600 hover:bg-slate-50 transition-colors">
            <Download size={18} />
            Export
          </button>
          <button 
            onClick={() => handleOpenModal()}
            className="flex items-center gap-2 px-6 py-2 bg-purple-600 text-white rounded-xl text-sm font-semibold hover:bg-purple-700 shadow-lg shadow-purple-200 transition-all"
          >
            <Plus size={18} />
            Tambah Barang
          </button>
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
        <div className="p-4 border-b border-slate-100 bg-slate-50/50 flex flex-col md:flex-row gap-4 items-center justify-between">
          <div className="relative w-full md:w-96">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Cari nama, kode, atau barcode..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-purple-500 transition-all"
            />
          </div>
          <div className="flex items-center gap-3">
